label.patternFunction:
var color;
if(data.active !== "true"){
    color = 'rgb(255, 0, 0)';
} else {
    color = 'rgb(39, 134, 34)';
}
return '<span style="border: solid ' + color + '; border-radius: 10px; color: ' + color + '; background-color: #fff; padding: 3px 5px; font-size: 14px; position: relative; bottom: 6px;">' + 
           '${entityLabel}' + 
        '</span>'

tooltip.patternFunction:
const unit = {
  from: '°C',
  METRIC: '°C',
  IMPERIAL: '°F',
  HYBRID: '°C'
}

var usrUnit = ctx.unitService.getTargetUnitSymbol(unit);

var unitValue = ctx.unitService.convertUnitValue(data.temperature, unit).toFixed(1);

return `<b>${data.entityName}</b><br/><br/><b>Temperature:</b> ${unitValue} ${usrUnit}<br/><b>Humidity:</b> ${data.humidity} %<br/><br/><link-act name="navigate_to_details">Sensor details</link-act><br/>`;
